mapper.select:
SELECT id, subject, chapter, title, content, keywords, importance, created_at FROM ai_knowledge_point
AND subject = #{subject}
AND (
title LIKE CONCAT('%', #{kw}, '%') OR keywords LIKE CONCAT('%', #{kw}, '%') OR content LIKE CONCAT('%', #{kw}, '%')
)
ORDER BY CASE WHEN importance = 'HIGH' THEN 0 WHEN importance = 'MEDIUM' THEN 1 ELSE 2 END, id ASC LIMIT #{limit}
